INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00999', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '超焦距遠距屈光（hyperfocaldistancerefraction）矯正方式，目的是在無調節力介入下，得到最寬廣的清晰 視覺距離的範圍。假設一患者的景深（depthoffield）是±0.25D，則該患者在超焦距遠距屈光矯正後，無 調節作用下清晰視覺距離的範圍為下列何者？', '["眼前4m至眼前2m", "眼前4m至眼前1m", "無限遠至眼前2m", "無限遠至眼前1m"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01000', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一般而言，6m距離被視為光學無限遠（opticalinfinity），故自覺式驗光多以此為標準檢查距離，而不正確 的檢查距離亦可能造成驗光結果誤差。若在4m距離為患者驗光的結果為+3.50DS/-1.00DC×090，不考慮 景深，則最終處方應如何修正，才能給予患者最佳的遠距屈光矯正？', '["+3.25DS/-1.00DC×090", "+3.75DS/-1.00DC×090", "+3.50DS/-1.25DC×090", "+3.50DS/-0.75DC×090"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01001', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '進行鐘面圖（clockchart,sunburstdial）檢測與傑克森交叉圓柱鏡（Jacksoncrosscylinder,JCC）檢測的比 較，下列敘述何者錯誤？', '["都是自覺式驗光", "都是先確認散光軸度，再確認散光度數", "都是在最正球面度最佳視力（MPMVA）下進行", "鐘面圖檢測不需要維持等價球面起始度，傑克森交叉圓柱鏡檢測則需要維持等價球面起始度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01002', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關遠視的敘述，下列何者錯誤？', '["需用凸透鏡矯正", "遠點為一虛像點", "看近物時比看遠物時所需的調節量更少", "一般年輕患者能夠透過調節而獲得相對清晰的遠距離視力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01003', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '依據 Hofstetter’s 的最小調節幅度公式，並採取保留一半調節幅度之原則，52 歲的受檢者要閱讀近距離 33cm的文件，需要多少加入度？', '["+1.50D", "+2.00D", "+2.50D", "+3.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01004', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者雙眼屈光度為-5.00DS/-1.50DC×175，融像性交叉圓柱鏡（FCC）檢查結果為+1.50D，以負相對調 節力（negativerelativeaccommodation,NRA）及正相對調節力（positiverelativeaccommodation,PRA）對暫 時加入度進行調整。若NRA為+2.00D，PRA為-1.50D，最終近距離單焦鏡片處方為下列何者？', '["-3.25DS/-1.50DC×175", "-3.00DS/-1.50DC×175", "-6.75DS/-1.50DC×175", "-7.00DS/-1.50DC×175"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01005', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關近距離附加度（ADD），下列敘述何者是最不合宜的考量？', '["大多數人兩眼的近距離附加度，通常是一樣的", "近距離附加度隨年齡增長而增多", "正常視力者，經常會給予+4.00D以上的近距離附加度", "近距離附加度的給予儘可能越低度越好，來維持較寬廣的明視區域"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01006', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者有遠視+2.00DS，習慣近用閱讀距離為40cm，用推進法或上推法（push-upmethod）測出調節力為', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01007', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '00D。若運用調節幅度一半原則（tentativeaddbasedonhalftheaccommodation）配製單焦老花眼鏡，此 眼鏡的鏡片度數為下列何者？', '["+1.00DS", "+2.00DS", "+3.00DS", "+4.00DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01008', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關執行最大正度數最佳矯正視力（maximumplustomaximumvisualacuity,MPMVA）檢查的方式與內容， 下列何者最不適當？', '["施行睫狀肌麻痺驗光（cycloplegicrefraction），有助檢查調節痙攣或隱藏性遠視者", "霧視（fogging）法可以放鬆被檢者的調節力", "操作傑克森交叉圓柱鏡必需加入正鏡片霧視被檢者視力以獲得準確屈光度數", "單眼視或兩眼單一視的自覺式驗光都需採用霧視法以放鬆被檢者的調節力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
